import Vue from 'vue'
import VueRouter from 'vue-router'
import store from '@/store'
import Dashboard from '@/views/Dashboard.vue'
import Reportes from '@/views/Reportes.vue'
import Vendedores from '@/views/Vendedores.vue'
import Login from '@/views/Login.vue'

Vue.use(VueRouter)

const routes = [
  {
    path: '/login',
    name: 'Login',
    component: Login,
    meta: { title: 'Acceso', guest: true }
  },
  {
    path: '/',
    redirect: '/dashboard'
  },
  {
    path: '/dashboard',
    name: 'Dashboard',
    component: Dashboard,
    meta: { title: 'Dashboard', requiresAuth: true }
  },
  {
    path: '/reportes',
    name: 'Reportes',
    component: Reportes,
    meta: { title: 'Reportes', requiresAuth: true }
  },
  {
    path: '/vendedores',
    name: 'Vendedores',
    component: Vendedores,
    meta: { title: 'Vendedores', requiresAuth: true }
  },
  {
    path: '/vendedor/panel',
    name: 'VendedorPanel',
    component: () => import('@/views/VendedorDashboard.vue'),
    meta: { title: 'Panel Vendedor', requiresAuth: true }
  }
]

const router = new VueRouter({
  mode: 'history',
  base: process.env.BASE_URL,
  routes
})

// Guard de navegación para proteger rutas
router.beforeEach((to, from, next) => {
  const isAuthenticated = store.getters.isAuthenticated

  if (to.matched.some(record => record.meta.requiresAuth)) {
    if (!isAuthenticated) {
      next('/login')
    } else {
      next()
    }
  } else if (to.matched.some(record => record.meta.guest)) {
    if (isAuthenticated) {
      next('/dashboard')
    } else {
      next()
    }
  } else {
    next()
  }
})

// Actualizar el título de la pestaña
router.afterEach((to) => {
  document.title = `${to.meta.title} | Sales Dashboard`
})

export default router
